package fr.ibrakash.helper.configuration.objects;

import org.bukkit.inventory.ItemStack;

/**
 * Interface for parsing custom items from third-party plugins
 * Supports ItemsAdder, Oraxen, and Nexo
 */
public interface CustomItemParser {
    /**
     * Attempts to parse a custom item from the given ID
     * @param customId the custom item identifier
     * @return ItemStack if found, null otherwise
     */
    ItemStack parseCustomItem(String customId);

    /**
     * Checks if this parser supports the given custom item ID
     * @param customId the custom item identifier
     * @return true if this parser can handle it
     */
    boolean supports(String customId);

    /**
     * Gets the priority of this parser (higher = checked first)
     * @return priority level
     */
    default int getPriority() {
        return 0;
    }
}

package fr.ibrakash.helper.configuration.objects;

import org.bukkit.inventory.ItemStack;

/**
 * Custom item parser for ItemsAdder plugin
 */
public class ItemsAdderParser implements CustomItemParser {

    private static ItemsAdderParser instance;

    private ItemsAdderParser() {}

    public static ItemsAdderParser getInstance() {
        if (instance == null) {
            instance = new ItemsAdderParser();
        }
        return instance;
    }

    @Override
    public ItemStack parseCustomItem(String customId) {
        try {
            // ItemsAdder format: namespace:id
            Class<?> itemsAdderAPIClass = Class.forName("dev.lone.itemsadder.api.CustomStack");
            Object customStack = itemsAdderAPIClass
                    .getMethod("getInstance", String.class)
                    .invoke(null, customId);

            if (customStack != null) {
                ItemStack itemStack = (ItemStack) customStack
                        .getClass()
                        .getMethod("getItemStack")
                        .invoke(customStack);
                return itemStack != null ? itemStack.clone() : null;
            }
        } catch (Exception e) {
            // ItemsAdder not available or custom item not found
        }
        return null;
    }

    @Override
    public boolean supports(String customId) {
        // ItemsAdder custom IDs are typically in format "namespace:id"
        return customId != null && customId.contains(":") && isItemsAdderAvailable();
    }

    @Override
    public int getPriority() {
        return 10;
    }

    private static boolean isItemsAdderAvailable() {
        try {
            Class.forName("dev.lone.itemsadder.api.CustomStack");
            return true;
        } catch (ClassNotFoundException e) {
            return false;
        }
    }
}

package fr.ibrakash.helper.configuration.objects;

import org.bukkit.inventory.ItemStack;

/**
 * Custom item parser for Nexo plugin
 */
public class NexoParser implements CustomItemParser {

    private static NexoParser instance;

    private NexoParser() {}

    public static NexoParser getInstance() {
        if (instance == null) {
            instance = new NexoParser();
        }
        return instance;
    }

    @Override
    public ItemStack parseCustomItem(String customId) {
        try {
            // Nexo API
            Class<?> nexoItemsClass = Class.forName("com.nexomc.nexo.items.ItemRegistry");
            Object registry = nexoItemsClass
                    .getMethod("getInstance")
                    .invoke(null);

            Object nexoItem = registry
                    .getClass()
                    .getMethod("getItem", String.class)
                    .invoke(registry, customId);

            if (nexoItem != null) {
                ItemStack itemStack = (ItemStack) nexoItem
                        .getClass()
                        .getMethod("getItem")
                        .invoke(nexoItem);
                return itemStack != null ? itemStack.clone() : null;
            }
        } catch (Exception e) {
            // Nexo not available or custom item not found
        }
        return null;
    }

    @Override
    public boolean supports(String customId) {
        return customId != null && isNexoAvailable();
    }

    @Override
    public int getPriority() {
        return 15;
    }

    private static boolean isNexoAvailable() {
        try {
            Class.forName("com.nexomc.nexo.items.ItemRegistry");
            return true;
        } catch (ClassNotFoundException e) {
            return false;
        }
    }
}

package fr.ibrakash.helper.configuration.objects;

import org.bukkit.inventory.ItemStack;

/**
 * Custom item parser for Oraxen plugin
 */
public class OraxenParser implements CustomItemParser {

    private static OraxenParser instance;

    private OraxenParser() {}

    public static OraxenParser getInstance() {
        if (instance == null) {
            instance = new OraxenParser();
        }
        return instance;
    }

    @Override
    public ItemStack parseCustomItem(String customId) {
        try {
            // Oraxen API
            Class<?> oraxenItemsAPIClass = Class.forName("io.th0rgal.oraxen.items.OraxenItems");
            Object oraxenItem = oraxenItemsAPIClass
                    .getMethod("getItemById", String.class)
                    .invoke(null, customId);

            if (oraxenItem != null) {
                ItemStack itemStack = (ItemStack) oraxenItem
                        .getClass()
                        .getMethod("build")
                        .invoke(oraxenItem);
                return itemStack != null ? itemStack.clone() : null;
            }
        } catch (Exception e) {
            // Oraxen not available or custom item not found
        }
        return null;
    }

    @Override
    public boolean supports(String customId) {
        return customId != null && !customId.contains(":") && isOraxenAvailable();
    }

    @Override
    public int getPriority() {
        return 20;
    }

    private static boolean isOraxenAvailable() {
        try {
            Class.forName("io.th0rgal.oraxen.items.OraxenItems");
            return true;
        } catch (ClassNotFoundException e) {
            return false;
        }
    }
}
